import{_ as a,o,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Create a User","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/create-user.md","filePath":"how-to/create-user.md"}'),s={name:"how-to/create-user.md"};function l(i,e,n,h,d,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="create-a-user" tabindex="-1">Create a User <a class="header-anchor" href="#create-a-user" aria-label="Permalink to &quot;Create a User&quot;">​</a></h1><p>Use the <strong>Users</strong> panel when you need to create an account for someone instead of waiting for them to register on their own. This is usually how a <code>Supreme Admin</code> or <code>King</code> sets up access for a new helper, leader, or <code>Alliance Player</code>.</p><blockquote><p>Screenshot placeholder: admin-user-create.png</p></blockquote><h2 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h2><ul><li>Make sure you know which kingdom or alliance this person belongs to.</li><li>Pick the right role label before you save: <code>Supreme Admin</code>, <code>King</code>, <code>Alliance Leader</code>, <code>Co-Leader</code>, or <code>Alliance Player</code>.</li><li>If you are a <code>King</code>, you can only create users inside the part of the system you manage.</li></ul><h2 id="create-the-account" tabindex="-1">Create the account <a class="header-anchor" href="#create-the-account" aria-label="Permalink to &quot;Create the account&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Find the <strong>Users</strong> section.</li><li>Fill in <strong>Username</strong> and <strong>Display name</strong>.</li><li>Add <strong>Email</strong> if the user should receive password emails.</li><li>Choose a <strong>Password</strong> only if you want to set one yourself.</li><li>Choose the user&#39;s <strong>Kingdom</strong>, <strong>Alliance</strong>, and <strong>Role</strong>.</li><li>Select <strong>Create user</strong>.</li></ol><h2 id="how-the-password-works" tabindex="-1">How the password works <a class="header-anchor" href="#how-the-password-works" aria-label="Permalink to &quot;How the password works&quot;">​</a></h2><ul><li>If you type a password, that password is saved for the new user.</li><li>If you leave <strong>Password</strong> blank, the system creates a password internally and marks the account to change it at first sign-in.</li><li>This page does not show or email that generated password back to you.</li></ul><p>Because of that, the safest workflow is usually one of these:</p><ul><li>Set a starting password yourself and tell the user privately.</li><li>Or create the user with an email address, then use the reset flow to send a one-time temporary password by email.</li></ul><h2 id="choosing-the-right-scope" tabindex="-1">Choosing the right scope <a class="header-anchor" href="#choosing-the-right-scope" aria-label="Permalink to &quot;Choosing the right scope&quot;">​</a></h2><ul><li><code>Supreme Admin</code> is a global account. It does not need a kingdom or alliance.</li><li><code>King</code> belongs to a kingdom.</li><li><code>Alliance Leader</code>, <code>Co-Leader</code>, and <code>Alliance Player</code> belong to an alliance.</li></ul><p>If the role needs a kingdom or alliance, the form requires it before it will save.</p><h2 id="what-happens-next" tabindex="-1">What happens next <a class="header-anchor" href="#what-happens-next" aria-label="Permalink to &quot;What happens next&quot;">​</a></h2><ul><li>The account appears in the user list right away.</li><li>From there you can open the profile, change details, add more assignments, or reset the password.</li><li>If the new person should manage more than one place, add those extra assignments after the account is created.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./edit-user.html">Edit a User &amp; Reset Their Password</a></li><li><a href="./assign-roles.html">Assign or Remove Roles</a></li><li><a href="./../roles/overview.html">Roles Explained</a></li><li><a href="./../getting-started/registering.html">Request an Account</a></li></ul>',18)])])}const p=a(s,[["render",l]]);export{g as __pageData,p as default};
